UP = Matrix.Rotation(math.radians(90), 4, 'X')   # game Y-up -> Blender Z-up for display

def build():
    # ---- armature ----
    arm = bpy.data.armatures.new("rig"); ao = bpy.data.objects.new("rig", arm)
    bpy.context.collection.objects.link(ao); bpy.context.view_layer.objects.active = ao
    bpy.ops.object.mode_set(mode='EDIT')
    eb = {}
    for i, b in enumerate(BONES):
        bone = arm.edit_bones.new(b["name"]); eb[i] = bone
        h = UP @ Vector(b["pos"]); bone.head = h; bone.tail = h + Vector((0, 0, 0.5))
    for i, b in enumerate(BONES):
        if b["parent"] >= 0: eb[i].parent = eb[b["parent"]]
    # point each bone at its first child so the chain reads as a spine
    for i, b in enumerate(BONES):
        kids = [eb[j] for j, bb in enumerate(BONES) if bb["parent"] == i]
        if kids: eb[i].tail = kids[0].head
    bpy.ops.object.mode_set(mode='OBJECT')

    # ---- mesh ----
    me = bpy.data.meshes.new("fish"); me.from_pydata([list(UP @ Vector(v)) for v in VERTS], [], TRIS)
    me.update(); mo = bpy.data.objects.new("fish", me); bpy.context.collection.objects.link(mo)
    md = mo.modifiers.new("arm", 'ARMATURE'); md.object = ao
    mo.parent = ao
    for i, b in enumerate(BONES): mo.vertex_groups.new(name=b["name"])   # empty groups to paint into

    # ---- one Action per motion (KEY range), pose-bone quaternion keyframes ----
    name_by_frame = {i: b["name"] for i, b in enumerate(BONES)}
    for mi, (s, e, label) in enumerate(KEYS):
        act = bpy.data.actions.new(f"m{mi}_{label}")
        ao.animation_data_create(); ao.animation_data.action = act
        for pb in ao.pose.bones: pb.rotation_mode = 'QUATERNION'
        for frameIdx, kfs in TRACKS.items():
            nm = name_by_frame.get(frameIdx);  pb = ao.pose.bones.get(nm) if nm else None
            if not pb: continue
            for (t, q) in kfs:
                if s <= t <= e:
                    pb.rotation_quaternion = Quaternion((q[0], q[1], q[2], q[3]))
                    pb.keyframe_insert("rotation_quaternion", frame=int(t - s))
        # stash as an NLA-free action; user picks it in the Action Editor
        ao.animation_data.action = None
        act.use_fake_user = True
    print("Built rig with", len(KEYS), "motion actions — pick one in the Action Editor to view.")

build()
